using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class PostCommentConfiguration : IEntityTypeConfiguration<PostComment>{public void Configure(EntityTypeBuilder<PostComment> builder){builder.ToTable("post_comments");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("comment_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.Content).IsRequired();builder.HasOne(e => e.Post).WithMany(p => p.Comments).HasForeignKey(e => e.PostId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.ParentComment).WithMany(c => c.Replies).HasForeignKey(e => e.ParentCommentId).OnDelete(DeleteBehavior.Restrict);builder.HasQueryFilter(e => e.DeletedAt == null);}}
